package com.spendwise.prototype.ui; import android.net.Uri; import android.os.Bundle; import android.view.View; import android.widget.*; import androidx.activity.result.contract.ActivityResultContracts; import androidx.core.content.FileProvider; import androidx.fragment.app.Fragment; import androidx.lifecycle.lifecycleScope; import com.spendwise.prototype.R; import com.spendwise.prototype.data.*; import kotlinx.coroutines.launch; import java.io.File; class AddExpenseFragment:Fragment(R.layout.fragment_add_expense){ private var photo:String?=null; private var cats=emptyList<Category>(); private val cam=registerForActivityResult(ActivityResultContracts.TakePicture()){ ok-> if(ok) view?.findViewById<ImageView>(R.id.ivPreview)?.setImageURI(photo?.let{Uri.fromFile(File(it))}) }; override fun onViewCreated(v:View,b:Bundle?){ val db=AppDatabase.get(requireContext()); val sp=v.findViewById<Spinner>(R.id.spCategory); lifecycleScope.launch{ db.categoryDao().getAll().collect{ l-> cats=l; sp.adapter=ArrayAdapter(requireContext(),android.R.layout.simple_spinner_item,l.map{it.name}) } }; v.findViewById<Button>(R.id.btnPhoto).setOnClickListener{ val f=File(requireContext().getExternalFilesDir("Pictures"),"r_${System.currentTimeMillis()}.jpg"); photo=f.absolutePath; val u=FileProvider.getUriForFile(requireContext(),"${requireContext().packageName}.fileprovider",f); cam.launch(u) }; v.findViewById<Button>(R.id.btnSave).setOnClickListener{ val a=v.findViewById<EditText>(R.id.etAmount).text.toString().toDoubleOrNull(); if(a==null){ Toast.makeText(context,"Enter amount",Toast.LENGTH_SHORT).show(); return@setOnClickListener }; val d=v.findViewById<EditText>(R.id.etDesc).text.toString(); val c=cats.getOrNull(sp.selectedItemPosition)?.id?:1L; lifecycleScope.launch{ db.expenseDao().insert(Expense(amount=a,description=d,categoryId=c,dateMillis=System.currentTimeMillis(),photoPath=photo)); Toast.makeText(context,"Saved",Toast.LENGTH_SHORT).show() } } } }